import{_ as o,o as c,c as d,ap as a}from"./chunks/framework.BaP7s1d0.js";const u=JSON.parse('{"title":"包 API 总览","description":"","frontmatter":{},"headers":[],"relativePath":"zh/api/packages.md","filePath":"zh/api/packages.md"}'),r={name:"zh/api/packages.md"};function i(t,e,l,s,h,n){return c(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="包-api-总览" tabindex="-1">包 API 总览 <a class="header-anchor" href="#包-api-总览" aria-label="Permalink to “包 API 总览”">​</a></h1><p>本页用于汇总当前 monorepo 中对外可用的包级 API。</p><h2 id="ptahjs-ui-vue" tabindex="-1"><code>@ptahjs/ui-vue</code> <a class="header-anchor" href="#ptahjs-ui-vue" aria-label="Permalink to “@ptahjs/ui-vue”">​</a></h2><p>Vue 集成主入口。</p><ul><li><code>createPtah(options)</code></li><li><code>useRuntimeApp(args)</code></li><li><code>useDesignerApp(args)</code></li><li>内置组件：<code>DesignerRoot</code>、<code>Preview</code>、<code>WorkspaceWidget</code>、<code>ScenesWidget</code>、<code>ModulesWidget</code>、<code>EventsWidget</code>、<code>ParameterWidget</code>、<code>RendererModule</code>、<code>FpsWidget</code></li><li>内置渲染器：<code>WebRenderer</code>、<code>SceneRenderer</code>、<code>FlowRenderer</code></li><li>同时透出 <code>@ptahjs/runtime</code> 和 <code>@ptahjs/designer</code> 的导出</li></ul><hr><h2 id="ptahjs-runtime" tabindex="-1"><code>@ptahjs/runtime</code> <a class="header-anchor" href="#ptahjs-runtime" aria-label="Permalink to “@ptahjs/runtime”">​</a></h2><p>基于 Kernel 的运行时层。</p><ul><li>类：<code>Runtime</code>、<code>FlowRunner</code>、<code>ProgramLoader</code></li><li>函数：<code>compilePageSchemaToSections</code>、<code>compilePageSchema</code>、<code>buildStackToTarget</code></li><li>同时透出 <code>@ptahjs/kernel</code> 的导出</li></ul><hr><h2 id="ptahjs-designer" tabindex="-1"><code>@ptahjs/designer</code> <a class="header-anchor" href="#ptahjs-designer" aria-label="Permalink to “@ptahjs/designer”">​</a></h2><p>设计时层。</p><ul><li>类：<code>Designer</code></li><li>Schema 工厂：<code>createRootAppSchema</code>、<code>createSceneSchema</code>、<code>createModuleSchema</code>、<code>createPropsSchema</code>、<code>createEventsSchema</code>、<code>createSlotsSchema</code></li><li>参数 Schema 工具：<code>numberProp</code>、<code>stringProp</code>、<code>booleanProp</code>、<code>selectProp</code>、<code>objectProp</code>、<code>arrayProp</code>、<code>groupProp</code></li><li>同时透出 <code>@ptahjs/dnd</code> 的导出</li></ul><hr><h2 id="ptahjs-kernel" tabindex="-1"><code>@ptahjs/kernel</code> <a class="header-anchor" href="#ptahjs-kernel" aria-label="Permalink to “@ptahjs/kernel”">​</a></h2><p>核心状态层。</p><ul><li>类：<code>Kernel</code>、<code>ResourceRepository</code>、<code>ModuleManager</code>、<code>LifecycleChain</code>、<code>SharedResource</code></li><li>IR 工具：<code>createEmptyIRGraph</code>、<code>clearIRGraph</code>、<code>IR_SECTIONS</code>、<code>RUNTIME_STATE_KEYS</code>、各类 selector（如 <code>getSceneById</code>、<code>getModuleById</code>）</li><li>常量：<code>MODULE_TYPE</code>、<code>EVENT_TYPE</code>、<code>RESOURCE_TYPE</code>、<code>LIFECYCLE_TYPE</code>、<code>ROOT_SECTION</code></li><li>编译应用函数：<code>applyCompiledSectionsToKernel</code></li></ul><hr><h2 id="ptahjs-dnd" tabindex="-1"><code>@ptahjs/dnd</code> <a class="header-anchor" href="#ptahjs-dnd" aria-label="Permalink to “@ptahjs/dnd”">​</a></h2><p>拖拽引擎。</p><ul><li>Core：<code>Dnd</code></li><li>Services：<code>DropService</code>、<code>MirrorService</code>、<code>AutoScrollService</code>、<code>DropIndicatorService</code>、<code>ActiveSelectionService</code>、<code>TransformControllerService</code></li></ul><hr><h2 id="ptahjs-shared" tabindex="-1"><code>@ptahjs/shared</code> <a class="header-anchor" href="#ptahjs-shared" aria-label="Permalink to “@ptahjs/shared”">​</a></h2><p>通用工具包。</p><p>包含工具函数（<code>cloneDeep</code>、<code>debounce</code>、<code>orderBy</code> 等）、事件基础设施（<code>EventDispatcher</code>）、hotkeys、storage、websocket 等能力。</p><hr><h2 id="ptahjs-tri-core-ptahjs-tri-extensions" tabindex="-1"><code>@ptahjs/tri-core</code> / <code>@ptahjs/tri-extensions</code> <a class="header-anchor" href="#ptahjs-tri-core-ptahjs-tri-extensions" aria-label="Permalink to “@ptahjs/tri-core / @ptahjs/tri-extensions”">​</a></h2><p>3D 引擎与扩展插件包。</p><ul><li><code>@ptahjs/tri-core</code>：<code>defineTri(args)</code> 及引擎/插件/特性导出</li><li><code>@ptahjs/tri-extensions</code>：核心插件、功能插件、默认插件数组导出</li></ul><hr><h2 id="构建工具相关包" tabindex="-1">构建工具相关包 <a class="header-anchor" href="#构建工具相关包" aria-label="Permalink to “构建工具相关包”">​</a></h2><ul><li><code>@ptahjs/build</code>：<code>buildConfig(options)</code></li><li><code>@ptahjs/vite-plugin-json</code>：Vite JSON 插件入口（<code>src/main.js</code>）</li></ul>',32)])])}const m=o(r,[["render",i]]);export{u as __pageData,m as default};
